#include<cstdio>
using namespace std;

int a[101];

int main()
{
	int n,x,s,sum=0;
	scanf("%d",&n);
	for (int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
	}
	scanf("%d",&s);
	for (int i=1;i<=n;i++)
	{
    	if(a[i]<=s)
        {
        	s-=a[i];
			sum++;
        }
    	else
        {
        	continue;
        }
	}
	printf("%d",sum);
	return 0;
}
